public static boolean validateHeader(Common _record)
{
    boolean isValidHeader = true;

    if (ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        switch (_record.TableId)
        {
            case tableNum(PurchAgreementHeader):
                isValidHeader = ETGPurchAgreementMandatoryValidation::validatePurchAgreementHeader(_record as PurchAgreementHeader);
                break;

            case tableNum(ETG_PurchaseAgreementHeader):
                isValidHeader = ETGPurchAgreementMandatoryValidation::validateETG_PurchAgreementHeader(_record as ETG_PurchaseAgreementHeader);
                break;

            case tableNum(AgreementHeaderDefault):
                isValidHeader = ETGPurchAgreementMandatoryValidation::validateAgreementHeaderDefault(_record as AgreementHeaderDefault);
                break;

            case tableNum(PurchAgreementHeaderDefault):
                isValidHeader = ETGPurchAgreementMandatoryValidation::validatePurchAgreementHeaderDefault(_record as PurchAgreementHeaderDefault);
                break;    

            default:
                isValidHeader = true;
        }
    }
    return isValidHeader;
}

public static boolean validateLine(Common _record)
{
    boolean isValidLine = true;

    if (ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        switch (_record.TableId)
        {
            case tableNum(AgreementLine):
                isValidLine = ETGPurchAgreementMandatoryValidation::validateALine(_record as AgreementLine);
                break;

            case tableNum(InventDim):
                isValidLine = ETGPurchAgreementMandatoryValidation::validateInventDim(_record as InventDim);
                break;

            case tableNum(AgreementLineQuantityCommitment):
                isValidLine = ETGPurchAgreementMandatoryValidation::validateAgrLineQtyCommitment(_record as AgreementLineQuantityCommitment);
                break;

            default:
                isValidLine = true;
        }
    }

    return isValidLine;
}

private static boolean validatePurchAgreementHeader(PurchAgreementHeader _record)
{
    boolean ret = true;

    if (!_record.AgreementClassification)
    {
        ret =checkFailed("Purchase agreement classification is mandatory.");
    }

    if (!_record.DocumentExternalReference)
    {
        ret =checkFailed("Document external reference is mandatory.");
    }
    return ret;
}

private static boolean validateETG_PurchAgreementHeader(ETG_PurchaseAgreementHeader _record)
{
    boolean ret = true;
    if (!_record.ToDatePort)
    {
        ret = checkFailed("To Date is mandatory.");
    }

    if (!_record.PortOfLoading)
    {
        ret = checkFailed("Port/Place of loading is mandatory.");
    }

    if (!_record.PortOfDischarge)
    {
        ret = checkFailed("Port/Place of discharge is mandatory.");
    }

    if (!_record.BuyerAccountNum)
    {
        ret = checkFailed("Buyer Account is mandatory.");
    }

    if (!_record.SellerAccountNum)
    {
        ret = checkFailed("Seller Account is mandatory.");
    }

    if (!_record.FromDatePort)
    {
        ret = checkFailed("From Date is mandatory.");
    }
    return ret;
}

private static boolean validateAgreementHeaderDefault(AgreementHeaderDefault _record)
{
    boolean ret = true;

    if (!_record.PaymentTerms)
    {
        ret = checkFailed("Terms of payment is mandatory.");
    }

    if (!_record.DeliveryMode)
    {
        ret = checkFailed("Mode of delivery is mandatory.");
    }

    if (!_record.DeliveryTerm)
    {
        ret = checkFailed("Delivery terms is mandatory.");
    }
    return ret;
}

private static boolean validatePurchAgreementHeaderDefault(PurchAgreementHeaderDefault _record)
{
    boolean ret = true;

    if(!_record.MethodOfPayment)
    {
        ret= checkFailed("Method of payment is mandatory");
    }

    return ret;
}

private static boolean validateALine(AgreementLine _record)
{
    boolean ret = true;

    if (!_record.ItemId)
    {
        ret = checkFailed("Item number is mandatory.");
    }
    if (!_record.ETGFinalPlaceOfDelivery)
    {
        ret = checkFailed("Final place of delivery is mandatory.");
    }

    return ret;
}

private static boolean validateInventDim(InventDim _record)
{
    boolean ret = true;
    if (!_record.ConfigId)
    {
        ret = checkFailed("Grade is mandatory. ");
    }

    if (!_record.InventSizeId)
    {
        ret = checkFailed("Size is mandatory. ");
    }

    if (!_record.InventColorId)
    {
        ret = checkFailed("Origin is mandatory.");
    }

    if (!_record.InventStyleId)
    {
        ret = checkFailed("Brand is mandatory.");
    }

    if (!_record.InventSiteId)
    {
        ret = checkFailed("Site is mandatory.");
    }

    if (!_record.InventLocationId)
    {
        ret = checkFailed("Warehouse is mandatory.");
    }
    return ret;
}

private static boolean validateAgrLineQtyCommitment(AgreementLineQuantityCommitment _record)
{
    boolean ret = true;
    if (!_record.CommitedQuantity)
    {
        ret = checkFailed("Quantity is mandatory.");
    }

    if (!_record.PricePerUnit)
    {
        ret = checkFailed("Unit price is mandatory.");
    }
    return ret;
}

public static boolean validateFormHeaders(FormRun _formRun)
{
    boolean ret = true;

    FormDataSource formDS1 = _formRun.dataSource(formDataSourceStr(PurchAgreement, PurchAgreementHeader ));
    if (formDS1 && formDS1.cursor())
        ret = ret && ETGPurchAgreementMandatoryValidation::validateHeader(formDS1.cursor());


    FormDataSource formDS2 = _formRun.dataSource(formDataSourceStr(PurchAgreement, ETG_PurchaseAgreementHeader ));
    if (formDS2 && formDS2.cursor())
        ret = ret && ETGPurchAgreementMandatoryValidation::validateHeader(formDS2.cursor());

    FormDataSource formDS3 = _formRun.dataSource(formDataSourceStr(PurchAgreement, AgreementHeaderDefault ));
    if (formDS3 && formDS3.cursor())
        ret = ret && ETGPurchAgreementMandatoryValidation::validateHeader(formDS3.cursor());

    FormDataSource formDS4 = _formRun.dataSource(formDataSourceStr(PurchAgreement, PurchAgreementHeaderDefault ));
    if (formDS4 && formDS4.cursor())
        ret = ret && ETGPurchAgreementMandatoryValidation::validateHeader(formDS4.cursor());

    return ret;
}

public static boolean validateFormLines(FormRun _formRun)
{
    boolean ret = true;

    FormDataSource formDS1 = _formRun.dataSource(formDataSourceStr(PurchAgreement, ALine));
    if (formDS1 && formDS1.cursor())
        ret = ret && ETGPurchAgreementMandatoryValidation::validateLine(formDS1.cursor());


    FormDataSource formDS2 = _formRun.dataSource(formDataSourceStr(PurchAgreement, InventDim));
    if (formDS2 && formDS2.cursor())
        ret = ret && ETGPurchAgreementMandatoryValidation::validateLine(formDS2.cursor());

    FormDataSource formDS3 = _formRun.dataSource(formDataSourceStr(PurchAgreement, ALine_AgreementLineQuantityCommitment));
    if (formDS3 && formDS3.cursor())
        ret = ret && ETGPurchAgreementMandatoryValidation::validateLine(formDS3.cursor());

    return ret;
}
